from flask import Flask, request, jsonify
import psycopg2
from psycopg2 import sql
import re
from functools import wraps

app = Flask(__name__)

# Database configuration
DB_CONFIG = {
    'host': 'localhost',
    'database': 'analytics_db',
    'user': 'analytics_user',
    'password': 'secure_password',
    'port': 5432
}

def validate_input(input_string, max_length=100):
    """Validate and sanitize input to prevent injection attacks"""
    if not isinstance(input_string, str):
        return False
    if len(input_string) > max_length:
        return False
    # Allow only alphanumeric, underscores, and dots (for column names)
    if not re.match(r'^[a-zA-Z0-9_.]+$', input_string):
        return False
    return True

def require_valid_table_column(f):
    """Decorator to validate table and column names"""
    @wraps(f)
    def wrapper(*args, **kwargs):
        table = request.args.get('table')
        columns = request.args.get('columns')
        
        if table and not validate_input(table):
            return jsonify({'error': 'Invalid table name'}), 400
            
        if columns and not validate_input(columns):
            return jsonify({'error': 'Invalid column names'}), 400
            
        return f(*args, **kwargs)
    return wrapper

def get_db_connection():
    """Create database connection"""
    try:
        conn = psycopg2.connect(**DB_CONFIG)
        return conn
    except Exception as e:
        raise Exception(f"Database connection failed: {str(e)}")

@app.route('/query', methods=['GET'])
@require_valid_table_column
def dynamic_query():
    """Execute dynamic SQL query based on API parameters"""
    try:
        table = request.args.get('table')
        columns = request.args.get('columns', '*')
        filters = request.args.get('filters')
        limit = request.args.get('limit', 1000, type=int)
        offset = request.args.get('offset', 0, type=int)
        
        # Validate limit and offset
        if limit > 10000:
            limit = 10000
        if offset < 0:
            offset = 0
            
        # Build base query
        if columns == '*':
            query = sql.SQL("SELECT * FROM {}")
        else:
            # Split columns and validate each
            column_list = [col.strip() for col in columns.split(',')]
            if not all(validate_input(col) for col in column_list):
                return jsonify({'error': 'Invalid column names'}), 400
            query = sql.SQL("SELECT {} FROM {}")
            columns_sql = sql.SQL(', ').join([sql.Identifier(col) for col in column_list])
            
        # Add table name
        if not validate_input(table):
            return jsonify({'error': 'Invalid table name'}), 400
            
        query = query.format(columns_sql, sql.Identifier(table)) if columns != '*' else query.format(sql.Identifier(table))
        
        # Handle filters
        if filters:
            filter_conditions = []
            filter_pairs = filters.split(';')
            
            for pair in filter_pairs:
                if '=' in pair:
                    key, value = pair.split('=', 1)
                    key = key.strip()
                    value = value.strip()
                    
                    if not validate_input(key, 50) or not validate_input(value, 100):
                        return jsonify({'error': 'Invalid filter parameters'}), 400
                        
                    filter_conditions.append(sql.SQL("{} = %s").format(sql.Identifier(key)))
                    
            if filter_conditions:
                query = sql.SQL("{} WHERE {}").format(query, sql.SQL(' AND ').join(filter_conditions))
        
        # Add limit and offset
        query = sql.SQL("{} LIMIT {} OFFSET {}").format(query, sql.Literal(limit), sql.Literal(offset))
        
        # Execute query
        conn = get_db_connection()
        cursor = conn.cursor()
        cursor.execute(query)
        
        # Get column names
        column_names = [desc[0] for desc in cursor.description]
        
        # Fetch results
        rows = cursor.fetchall()
        results = [dict(zip(column_names, row)) for row in rows]
        
        cursor.close()
        conn.close()
        
        return jsonify({
            'status': 'success',
            'data': results,
            'count': len(results)
        })
        
    except psycopg2.Error as e:
        return jsonify({'error': f'Database error: {str(e)}'}), 500
    except Exception as e:
        return jsonify({'error': f'Internal error: {str(e)}'}), 500

@app.route('/tables', methods=['GET'])
def get_tables():
    """Get list of available tables"""
    try:
        conn = get_db_connection()
        cursor = conn.cursor()
        
        query = """
        SELECT table_name 
        FROM information_schema.tables 
        WHERE table_schema = 'public'
        ORDER BY table_name
        """
        
        cursor.execute(query)
        tables = [row[0] for row in cursor.fetchall()]
        
        cursor.close()
        conn.close()
        
        return jsonify({
            'status': 'success',
            'tables': tables
        })
        
    except Exception as e:
        return jsonify({'error': f'Internal error: {str(e)}'}), 500

